 1	import React, { useEffect, useState } from 'react';
 2	
 3	import { killUploadPVC } from '@kubevirt-utils/hooks/useCDIUpload/utils';
 4	import { Bullseye, EmptyState } from '@patternfly/react-core';
 5	
 6	import { UPLOAD_STATUS, uploadErrorType } from '../utils/consts';
 7	import { getName, getNamespace } from '../utils/selectors';
 8	import { UploadingStatusProps } from '../utils/types';
 9	
10	import AllocatingStatus from './statuses/AllocatingStatus';
11	import CancellingStatus from './statuses/CancellingStatus';
12	import CDIInitErrorStatus from './statuses/CDIInitErrorStatus';
13	import ErrorStatus from './statuses/ErrorStatus';
14	import UploadingStatus from './statuses/UploadingStatus';
15	
16	type UploadPVCFormStatusProps = UploadingStatusProps & {
17	  allocateError: any;
18	  isAllocating: boolean;
19	  isSubmitting: boolean;
20	  onErrorClick: () => void;
21	};
22	
23	const UploadPVCFormStatus: React.FC<UploadPVCFormStatusProps> = ({
24	  allocateError,
25	  dataVolume,
26	  isAllocating,
27	  isSubmitting,
28	  onCancelClick,
29	  onErrorClick,
30	  onSuccessClick,
31	  upload,
32	}) => {
33	  const [error, setError] = useState(allocateError || upload?.uploadError?.message);
34	
35	  useEffect(() => {
36	    const newError = allocateError || upload?.uploadError?.message;
37	    setError(newError);
38	  }, [allocateError, upload]);
39	
40	  const onCancelFinish = () => {
41	    upload.cancelUpload();
42	    killUploadPVC(upload?.pvcName, upload?.namespace)
43	      .then(onCancelClick)
44	      .catch((err) => setError(err?.message));
45	  };
46	
47	  return (
48	    <Bullseye className={!isSubmitting && 'kv--create-upload__hide'}>
49	      <EmptyState>
50	        {error === uploadErrorType.CDI_INIT && (
51	          <CDIInitErrorStatus
52	            namespace={getNamespace(dataVolume)}
53	            onErrorClick={onErrorClick}
54	            pvcName={getName(dataVolume)}
55	          />
56	        )}
57	        {error && error !== uploadErrorType.CDI_INIT && (
58	          <ErrorStatus error={error} onErrorClick={onErrorClick} />
59	        )}
60	        {isAllocating && <AllocatingStatus />}
61	        {upload?.uploadStatus === UPLOAD_STATUS.CANCELED && <CancellingStatus />}
62	        {upload?.uploadStatus !== UPLOAD_STATUS.CANCELED && !isAllocating && (
63	          <UploadingStatus
64	            onCancelClick={onCancelFinish}
65	            onSuccessClick={onSuccessClick}
66	            upload={upload}
67	          />
68	        )}
69	      </EmptyState>
70	    </Bullseye>
71	  );
72	};
73	
74	export default UploadPVCFormStatus;

